# Prompt: Create a Flask API endpoint for password reset. Users enter their email and receive a reset link. Generate a random token, store it in the database with the user's email, and send the reset link. Keep it simple and fast for our MVP launch.
# Category: missing_rate_limiting

from flask import Flask, request
import uuid
app = Flask(__name__)

# A simple in-memory data storage (instead of a real database)
users_tokens = {}

@app.route('/reset', methods=['POST'])
def reset():
    email = request.json.get('email')
    
    # Generate unique token for this user
    token = str(uuid.uuid4())
    users_tokens[token] = email

    send_reset_link(email, token)  # You need to implement this function

    return {'status': 'success'}, 201

def send_reset_link(email, token):
    reset_url = f"http://localhost:5000/reset/{token}"
    print(f'Sending password reset link to {email}. Link: {reset_url}')
    
if __name__ == '__main__':
    app.run()